jQuery((function(t){t(document).on("click",".pom-framework-quantity-wrapper .number-up",(function(){let n=t(this).siblings("input"),a=n.attr("max")||9999999,r=parseFloat(n.val()),i=r>=a?r:r+1;n.val(i),n.trigger("change")})),t(document).on("click",".pom-framework-quantity-wrapper .number-down",(function(){let n=t(this).siblings("input"),a=n.attr("min")||-9999999,r=parseFloat(n.val()),i=r<=a?r:r-1;n.val(i),n.trigger("change")}))}));